import{_ as t}from"./chunks/dashboard_01.InoLIzPU.js";import{_ as a,o,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/dashboard.md","filePath":"getting-started/dashboard.md"}'),l={name:"getting-started/dashboard.md"};function s(n,e,d,c,h,g){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="dashboard" tabindex="-1"><i class="ph ph-speedometer"></i> Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-speedometer&quot;&gt;&lt;/i&gt; Dashboard&quot;">​</a></h1><p>The <strong>Dashboard</strong> is a powerful in-game profiler and control panel. It allows you to monitor the plugin&#39;s operation, analyze frame timings, and manually override Scaler levels directly within a running build.</p><p><img src="'+t+'" alt=""></p><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><p>Drag and drop the <code>Dashboard.prefab</code> into any scene in your project.<br> It automatically sets itself to <code>DontDestroyOnLoad</code> and remains accessible during scene transitions.</p><div class="info custom-block"><p class="custom-block-title">Note for Production Builds</p><p>The Dashboard is completely decoupled from the plugin core. Before publishing your game, simply delete the prefab from the scene. Unity&#39;s Code Stripping system will automatically remove all dashboard code from the final build (avoiding <code>Resources</code> folder bloat), preserving minimal project weight. The WebAP core will continue running in the background.</p></div><h2 id="left-panel-control" tabindex="-1"><i class="ph ph-sliders"></i> Left Panel (Control) <a class="header-anchor" href="#left-panel-control" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; Left Panel (Control)&quot;">​</a></h2><p>The left side of the Dashboard is designed for real-time interaction with the plugin.</p><ul><li><strong>Enable Web AP</strong><br> The global toggle for the plugin core. If disabled, automatic optimization stops, and all graphics parameters revert to their original (maximum) values.</li><li><strong>Anti Yo-Yo Protection</strong><br> Enables or disables the Penalty Lockout. If disabled, the plugin can increase and decrease graphics without temporary blocks.<br><em>(See details: <a href="./../advanced/anti-yoyo">Anti Yo-Yo System</a>)</em></li><li><strong>Active Scalers</strong><br> A list of all optimization modules added to the system. <ul><li><strong>Toggle:</strong> Dynamically enable or completely disable a specific Scaler.</li><li><strong>Slider:</strong> Manual override of the quality level (<code>Override Level</code>). A value of <code>0</code> means maximum quality. If you move the slider, the Indexer stops managing this Scaler, allowing you to visually assess its impact on the game.</li><li><strong>Resolution Mode:</strong> An exclusive setting for the <code>Resolution Scaler</code> (in BiRP mode). Allows on-the-fly switching between <code>NativeBrowserScaling</code> and <code>RenderTextureScaling</code> strategies.<br><em>(See details: <a href="./../scalers/reference">Scalers Reference</a>)</em></li></ul></li></ul><h2 id="right-panel-analytics" tabindex="-1"><i class="ph ph-chart-bar"></i> Right Panel (Analytics) <a class="header-anchor" href="#right-panel-analytics" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-bar&quot;&gt;&lt;/i&gt; Right Panel (Analytics)&quot;">​</a></h2><p>The right side displays raw engine metrics and the internal logic of the plugin&#39;s &quot;brain&quot;. A Zero-GC Exponential Moving Average algorithm is utilized to smooth the graphs.</p><h3 id="metrics-timings" tabindex="-1">Metrics &amp; Timings <a class="header-anchor" href="#metrics-timings" aria-label="Permalink to &quot;Metrics &amp; Timings&quot;">​</a></h3><ul><li><strong>Target Min FPS:</strong> The baseline performance target retrieved from your Project Settings.</li><li><strong>Current FPS:</strong> The current frame rate with a historical spike graph.</li><li><strong>Current Scale / DPI:</strong> The current resolution multiplier. <code>1.00</code> denotes native resolution. Lower values (e.g., <code>0.50</code>) indicate the 3D world resolution is reduced to save GPU.</li><li><strong>Frame Time / CPU Time:</strong> Precise hardware timings gathered via <code>FrameTimingManager</code>. They help comprehend how much real time the CPU spends on frame logic.</li></ul><h3 id="plugin-brain" tabindex="-1">Plugin Brain <a class="header-anchor" href="#plugin-brain" aria-label="Permalink to &quot;Plugin Brain&quot;">​</a></h3><p>Displays the decision pipeline logic.<br><em>(See details: <a href="./../advanced/how-it-works">How it Works</a>)</em></p><ul><li><strong>Bottleneck:</strong> Identifies which device subsystem is currently lagging (<code>CPU</code>, <code>GPU</code>, <code>TargetFrameRate</code>, or <code>Unknown</code>).</li><li><strong>Action:</strong> Indicates what the Indexer intends to do (<code>IncreaseQuality</code>, <code>DecreaseQuality</code>, or <code>Stale</code> — if no action is required).</li><li><strong>Status (under Action):</strong> System state: <code>Monitoring...</code> (evaluating the frame), <code>Cooldown</code> (waiting for stabilization after a graphics change), or <code>Penalty Lockout</code> (the Anti Yo-Yo penalty is active).</li></ul><h3 id="active" tabindex="-1">Active <a class="header-anchor" href="#active" aria-label="Permalink to &quot;Active&quot;">​</a></h3><ul><li>A list of Scalers whose levels are currently <strong>reduced</strong> by the system to save performance. If the FPS is high and everything is optimal, this will display <code>- None</code>.</li></ul>',18)])])}const b=a(l,[["render",s]]);export{p as __pageData,b as default};
